@RestController
class ProductController {
    private final ProductService productService;

    ProductController(ProductService productService) {
        this.productService = productService;
    }

    @org.springframework.web.bind.annotation.PostMapping("/api/products")
    public Map<String, Object> indexProduct(@org.springframework.web.bind.annotation.RequestBody Product product) throws IOException {
        productService.indexProduct(product);
        return Map.of("status", "indexed", "id", product.getId());
    }

    @org.springframework.web.bind.annotation.PostMapping("/api/search")
    public ProductSearchResponse search(@org.springframework.web.bind.annotation.RequestBody ProductSearchRequest request,
                                        @org.springframework.web.bind.annotation.RequestHeader(value = "X-User-Id", required = false) String userId) throws IOException {
        return productService.searchProducts(request, userId == null ? "anonymous" : userId);
    }
}